const safeParse = (value) => {
    if (!value || typeof value !== 'string') return null
    try {
        return JSON.parse(value)
    } catch {
        return null
    }
}

const sanitize = (value) =>
    String(value || '')
        .replace(/[<>:"/\|?*�-]/g, ' ')
        .replace(/s+/g, ' ')
        .trim()

const profile = safeParse($taskProfile) || {}
let exportTitle = sanitize(profile.topic || profile.targetVenue || '')

if (!exportTitle) {
    const lines = String($finalPaperPackage || '')
        .split(/?
/)
        .map((line) => line.trim())
        .filter(Boolean)

    const ignored = new Set(['# 终稿', '# 修改说明', '# 投稿前检查表'])
    const candidate = lines.find((line) => !ignored.has(line))
    exportTitle = sanitize(candidate ? candidate.replace(/^#+s*/, '') : '')
}

if (!exportTitle) {
    exportTitle = 'paper-final'
}

return {
    exportTitle
}
